function assertEvmChain(params, context) {
  const chain2 = params.chain ?? context.chain;
  if (chain2.type !== "evm") {
    throw new KitError({
      ...InputError.INVALID_CHAIN,
      recoverability: "FATAL",
      message: `Expected EVM chain definition, but received chain type: ${chain2.type}`
    });
  }
  return chain2;
}
function getGatewayMinterAddress(chain2) {
  if (!isGatewayV1Supported(chain2)) {
    throw new KitError({
      ...InputError.INVALID_CHAIN,
      recoverability: "FATAL",
      message: `Gateway Minter address not found: chain "${chain2.name}" does not have Gateway v1 contracts configured.`,
      cause: { trace: { chain: chain2.name } }
    });
  }
  return chain2.gateway.contracts.v1.minter;
}
